/**
 * @summary List daily login records
 */
export const getGetDailyLoginsUrl = (params?: GetDailyLoginsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/daily-logins?${stringifiedParams}`
    : `/api/daily-logins`;
};

export const getDailyLogins = async (
  params?: GetDailyLoginsParams,
  options?: RequestInit,
): Promise<DailyLogin[]> => {
  return customFetch<DailyLogin[]>(getGetDailyLoginsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetDailyLoginsQueryKey = (params?: GetDailyLoginsParams) => {
  return [`/api/daily-logins`, ...(params ? [params] : [])] as const;
};

